MERGE INTO CONSULTAS FIN USING (SELECT '002513INF_FAC_IDCBIS' INFORME ,TO_CLOB(q'[SELECT DISTINCT SF_FACTURA.NUMERO_FACTURA, 
	SF_FACTURA.TIPO_FACTURA, 
	TERCERO.NOMBRE, SF_FACTURA.TERCERO, 
	TERCERO.TELEFONOS, TERCERO.DIRECCION,CIUDAD.NOMBRE CIUDAD, SF_FACTURA.CENTRO_COSTO,
	 TERCERO.DIRECCIONEMAIL, SF_FACTURA.FECHA_EXPEDICION, 
	 SF_FACTURA.FECHA_VENCIMIENTO FROM SF_DETALLE_FACTURA
	 INNER JOIN SF_FACTURA ON SF_DETALLE_FACTURA.FACTURA = SF_FACTURA.NUMERO_FACTURA AND SF_DETALLE_FACTURA.TIPO_FACTURA = SF_FACTURA.TIPO_FACTURA AND SF_DETALLE_FACTURA.COMPANIA = SF_FACTURA.COMPANIA
	 INNER JOIN SF_TIPO_COBRO ON SF_FACTURA.COMPANIA = SF_TIPO_COBRO.COMPANIA AND SF_FACTURA.TIPO_FACTURA = SF_TIPO_COBRO.CODIGO AND SF_DETALLE_FACTURA.ANO = SF_TIPO_COBRO.ANO 
	 INNER JOIN TERCERO ON SF_FACTURA.COMPANIA = TERCERO.COMPANIA AND SF_FACTURA.TERCERO = TERCERO.NIT AND SF_FACTURA.SUCURSAL = TERCERO.SUCURSAL 
	 INNER JOIN SF_CONCEPTOS ON SF_CONCEPTOS.COMPANIA = SF_DETALLE_FACTURA.COMPANIA AND SF_CONCEPTOS.ANO = SF_DETALLE_FACTURA.ANO AND SF_CONCEPTOS.TIPOCOBRO = SF_DETALLE_FACTURA.TIPOCOBRO AND SF_CONCEPTOS.CODIGO = SF_DETALLE_FACTURA.CONCEPTO 
	 INNER JOIN CIUDAD ON CIUDAD.DEPARTAMENTO = TERCERO.DEPARTAMENTO AND CIUDAD.CODIGO = TERCERO.CIUDAD WHERE  SF_FACTURA.COMPANIA =  s$compania$s AND SF_FACTURA.TIPO_FACTURA   = 's$tipoFactura$s'
    AND SF_FACTURA.NUMERO_FACTURA BETWEEN s$facturaInicial$s AND s$facturaFinal$s
   AND SF_FACTURA.fecha_pago IS NULL
      AND ANULADA IN (0)]') CONSULTA, 69 APLICACION ,TO_CLOB(q'[]') CONSULTA_OPCIONAL, 'MROSERO' CREATED_BY, NULL MODIFIED_BY  FROM DUAL ) INI ON (INI.INFORME = FIN.INFORME )  WHEN MATCHED THEN  UPDATE SET FIN.CONSULTA =  INI.CONSULTA, FIN.APLICACION =  INI.APLICACION, FIN.CONSULTA_OPCIONAL =  INI.CONSULTA_OPCIONAL, FIN.MODIFIED_BY = INI.MODIFIED_BY, FIN.DATE_MODIFIED = SYSDATE  WHEN NOT MATCHED THEN  INSERT (INFORME,CONSULTA, APLICACION,CONSULTA_OPCIONAL,CREATED_BY,DATE_CREATED)  VALUES (INI.INFORME,INI.CONSULTA, INI.APLICACION,INI.CONSULTA_OPCIONAL,INI.CREATED_BY,SYSDATE);